# /etc/nginx/nginx.conf - Secure header configuration

http {
    # Hide Nginx version in Server header and error pages
    server_tokens off;

    # Additional security headers
    more_clear_headers 'Server';
    more_clear_headers 'X-Powered-By';
    more_clear_headers 'X-AspNet-Version';
    more_clear_headers 'X-AspNetMvc-Version';

    # Add security response headers
    more_set_headers 'X-Content-Type-Options: nosniff';
    more_set_headers 'X-Frame-Options: DENY';
    more_set_headers 'X-XSS-Protection: 1; mode=block';
    more_set_headers 'Strict-Transport-Security: max-age=31536000; includeSubDomains; preload';

    # Define custom error pages (prevent information leakage)
    error_page 400 401 402 403 404 /40x.html;
    error_page 500 502 503 504 /50x.html;

    # Upstream backend configuration
    upstream backend_service {
        server 10.0.1.100:8080;
        server 10.0.1.101:8080 backup;
    }

    server {
        listen 443 ssl http2;
        server_name api.example.com;

        # SSL configuration
        ssl_certificate /etc/nginx/ssl/cert.pem;
        ssl_certificate_key /etc/nginx/ssl/key.pem;
        ssl_protocols TLSv1.2 TLSv1.3;
        ssl_ciphers HIGH:!aNULL:!MD5;

        location /api/ {
            proxy_pass http://backend_service;

            # Remove headers from backend response
            proxy_hide_header Server;
            proxy_hide_header X-Powered-By;
            proxy_hide_header X-AspNet-Version;
            proxy_hide_header X-AspNetMvc-Version;
            proxy_hide_header X-Runtime;

            # Standard proxy headers (without revealing internal IPs)
            proxy_set_header Host $host;
            proxy_set_header X-Real-IP $remote_addr;
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_set_header X-Forwarded-Proto $scheme;

            # Do NOT send Via header
            proxy_set_header Via "";

            # Error handling (prevent backend error exposure)
            proxy_intercept_errors on;
        }

        # Custom error pages
        location = /40x.html {
            root /usr/share/nginx/html;
            internal;
        }

        location = /50x.html {
            root /usr/share/nginx/html;
            internal;
        }
    }
}

# Note: The 'more_clear_headers' and 'more_set_headers' directives require
# the headers-more-nginx-module. Install with:
# apt-get install nginx-extras  # Debian/Ubuntu
# OR compile Nginx with: --add-module=/path/to/headers-more-nginx-module
